{
  "sentences": [
    {
      "text": "我想確認明天的預約時間。",
      "pinyin": "Wǒ xiǎng quèrèn míngtiān de yùyuē shíjiān.",
      "pinyin_numeric": "wo3 xiang3 que4ren4 ming2tian1 de yu4yue1 shi2jian1.",
      "translation_en": "I want to confirm the appointment time for tomorrow.",
      "translation_ko": "내일 예약 시간을 확인하고 싶습니다."
    },
    {
      "text": "他打電話確認預約的日期。",
      "pinyin": "Tā dǎ diànhuà quèrèn yùyuē de rìqī.",
      "pinyin_numeric": "ta1 da3 dian4hua4 que4ren4 yu4yue1 de ri4qi1.",
      "translation_en": "He called to confirm the appointment date.",
      "translation_ko": "그는 전화로 예약 날짜를 확인했습니다."
    },
    {
      "text": "我們想確認預約的時段。",
      "pinyin": "Wǒmen xiǎng quèrèn yùyuē de shíduàn.",
      "pinyin_numeric": "wo3men xiang3 que4ren4 yu4yue1 de shi2duan4.",
      "translation_en": "We want to confirm the appointment time slot.",
      "translation_ko": "저희는 예약 시간대를 확인하고 싶습니다."
    },
    {
      "text": "她需要確認預約的號碼。",
      "pinyin": "Tā xūyào quèrèn yùyuē de hàomǎ.",
      "pinyin_numeric": "ta1 xu1yao4 que4ren4 yu4yue1 de hao4ma3.",
      "translation_en": "She needs to confirm the appointment number.",
      "translation_ko": "그녀는 예약 번호를 확인해야 합니다."
    },
    {
      "text": "你應該確認預約的狀態。",
      "pinyin": "Nǐ yīnggāi quèrèn yùyuē de zhuàngtài.",
      "pinyin_numeric": "ni3 ying1gai1 que4ren4 yu4yue1 de zhuang4tai4.",
      "translation_en": "You should confirm the appointment status.",
      "translation_ko": "예약 상태를 확인하셔야 합니다."
    },
    {
      "text": "我想確認預約的細節。",
      "pinyin": "Wǒ xiǎng quèrèn yùyuē de xìjié.",
      "pinyin_numeric": "wo3 xiang3 que4ren4 yu4yue1 de xi4jie2.",
      "translation_en": "I want to confirm the details of the appointment.",
      "translation_ko": "예약 세부 사항을 확인하고 싶습니다."
    },
    {
      "text": "他想要確認預約的記錄。",
      "pinyin": "Tā xiǎng yào quèrèn yùyuē de jìlù.",
      "pinyin_numeric": "ta1 xiang3 yao4 que4ren4 yu4yue1 de ji4lu4.",
      "translation_en": "He wants to confirm the appointment record.",
      "translation_ko": "그는 예약 기록을 확인하고 싶어 합니다."
    },
    {
      "text": "我們必須確認預約的日期和時間。",
      "pinyin": "Wǒmen bìxū quèrèn yùyuē de rìqī hé shíjiān.",
      "pinyin_numeric": "wo3men bi4xu1 que4ren4 yu4yue1 de ri4qi1 he2 shi2jian1.",
      "translation_en": "We must confirm the appointment date and time.",
      "translation_ko": "예약 날짜와 시간을 확인해야 합니다."
    },
    {
      "text": "她打算確認預約的行程。",
      "pinyin": "Tā dǎsuàn quèrèn yùyuē de xíngchéng.",
      "pinyin_numeric": "ta1 da3suan4 que4ren4 yu4yue1 de xing2cheng2.",
      "translation_en": "She plans to confirm the appointment schedule.",
      "translation_ko": "그녀는 예약 일정을 확인할 계획입니다."
    },
    {
      "text": "你應該先確認預約的提醒。",
      "pinyin": "Nǐ yīnggāi xiān quèrèn yùyuē de tíxǐng.",
      "pinyin_numeric": "ni3 ying1gai1 xian1 que4ren4 yu4yue1 de ti2xing3.",
      "translation_en": "You should first confirm the appointment reminder.",
      "translation_ko": "먼저 예약 알림을 확인하셔야 합니다."
    }
  ]
}
